export function searchEmoji(query: string, limit = 8): { shortcode: string; emoji: string }[] {
  const lower = query.toLowerCase()
  const results: { shortcode: string; emoji: string; score: number }[] = []
  for (const [shortcode, emoji] of Object.entries(EMOJI_SHORTCODES)) {
    if (shortcode.startsWith(lower)) {
      results.push({ shortcode, emoji, score: 0 }) // prefix match = best
    } else if (shortcode.includes(lower)) {
      results.push({ shortcode, emoji, score: 1 }) // substring match
    }
  }
  // Deduplicate by emoji вҖ” keep the best (lowest score, shortest name) match per emoji
  const seen = new Map<string, typeof results[0]>()
  for (const r of results) {
    const existing = seen.get(r.emoji)
    if (!existing || r.score < existing.score || (r.score === existing.score && r.shortcode.length < existing.shortcode.length)) {
      seen.set(r.emoji, r)
    }
  }
  const deduped = [...seen.values()]
  deduped.sort((a, b) => a.score - b.score || a.shortcode.length - b.shortcode.length)
  return deduped.slice(0, limit).map(({ shortcode, emoji }) => ({ shortcode, emoji }))
}
